CREATE TABLE `emp_bonus` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `emp_id` bigint NOT NULL,
  `bonus_id` bigint DEFAULT NULL,
  `processing_batch_id` bigint DEFAULT NULL COMMENT 'FK to bonus_processing_batch',
  `status` varchar(20) NOT NULL DEFAULT 'PENDING' COMMENT 'PENDING | APPROVED | PROCESSED | CANCELLED',
  `payroll_month` varchar(20) NOT NULL,
  `amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `adjusted_amount` decimal(15,2) DEFAULT NULL COMMENT 'Override amount set by approver; NULL means use calculated amount',
  `formula_expression` varchar(500) DEFAULT NULL COMMENT 'MVEL expression used during calculation',
  `formula_result` decimal(15,2) DEFAULT NULL COMMENT 'Raw MVEL evaluation result',
  `approved_by` bigint DEFAULT NULL,
  `approved_date` timestamp NULL DEFAULT NULL,
  `note` varchar(500) DEFAULT NULL COMMENT 'Reason for adjustment or other audit note',
  `is_processed` char(1) NOT NULL DEFAULT 'N',
  `processed_date` datetime DEFAULT NULL,
  `created_by` bigint NOT NULL,
  `created_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `modified_by` bigint NOT NULL,
  `modified_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `import_log_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_emp_bonus` (`emp_id`,`payroll_month`),
  KEY `fk_emp_bonus_emp_id` (`emp_id`),
  KEY `fk_emp_bonus_created_by` (`created_by`),
  KEY `fk_emp_bonus_modified_by` (`modified_by`),
  KEY `idx_emp_bonus_month` (`emp_id`,`payroll_month`),
  KEY `fk_emp_bonus_bonus` (`bonus_id`),
  KEY `fk_emp_bonus_import_log` (`import_log_id`),
  KEY `fk_emp_bonus_approved_by` (`approved_by`),
  KEY `idx_emp_bonus_batch` (`processing_batch_id`),
  CONSTRAINT `fk_emp_bonus_approved_by` FOREIGN KEY (`approved_by`) REFERENCES `usr` (`id`),
  CONSTRAINT `fk_emp_bonus_batch` FOREIGN KEY (`processing_batch_id`) REFERENCES `bonus_processing_batch` (`id`),
  CONSTRAINT `fk_emp_bonus_bonus` FOREIGN KEY (`bonus_id`) REFERENCES `bonus` (`id`),
  CONSTRAINT `fk_emp_bonus_created_by` FOREIGN KEY (`created_by`) REFERENCES `usr` (`id`),
  CONSTRAINT `fk_emp_bonus_emp_id` FOREIGN KEY (`emp_id`) REFERENCES `employee` (`id`),
  CONSTRAINT `fk_emp_bonus_import_log` FOREIGN KEY (`import_log_id`) REFERENCES `import_log` (`id`),
  CONSTRAINT `fk_emp_bonus_modified_by` FOREIGN KEY (`modified_by`) REFERENCES `usr` (`id`),
  CONSTRAINT `chk_emp_bonus_processed` CHECK ((`is_processed` in (_utf8mb4'Y',_utf8mb4'N'))),
  CONSTRAINT `chk_emp_bonus_status` CHECK ((`status` in (_utf8mb4'PENDING',_utf8mb4'APPROVED',_utf8mb4'PROCESSED',_utf8mb4'CANCELLED')))
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
