--
-- Table structure for table `emp_payroll_run`
--

DROP TABLE IF EXISTS `emp_payroll_run`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `emp_payroll_run` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `emp_id` bigint NOT NULL,
  `payroll_month` varchar(20) NOT NULL,
  `basic_salary` decimal(15,2) NOT NULL DEFAULT '0.00',
  `total_allowances` decimal(15,2) NOT NULL DEFAULT '0.00',
  `total_deductions` decimal(15,2) NOT NULL DEFAULT '0.00',
  `gross_pay` decimal(15,2) NOT NULL DEFAULT '0.00',
  `net_pay` decimal(15,2) NOT NULL DEFAULT '0.00',
  `status` varchar(20) NOT NULL DEFAULT 'DRAFT' COMMENT 'DRAFT | PROCESSED | LOCKED | CORRECTION_DRAFT | CORRECTION_LOCKED',
  `processed_date` datetime DEFAULT NULL,
  `processed_by` bigint DEFAULT NULL,
  `created_by` bigint NOT NULL,
  `created_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `modified_by` bigint NOT NULL,
  `modified_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `run_type` varchar(20) NOT NULL DEFAULT 'NORMAL' COMMENT 'NORMAL | CORRECTION',
  `parent_run_id` bigint DEFAULT NULL COMMENT 'For CORRECTION runs: FK to the original LOCKED run',
  `epf_liable_base` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Base used for EPF/ETF computation',
  `taxable_earnings` decimal(15,2) NOT NULL DEFAULT '0.00',
  `employee_epf` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Employee EPF deduction (8%)',
  `employer_epf` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Employer EPF contribution (12%)',
  `etf` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'ETF contribution (3%)',
  `paye_tax` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'PAYE income tax deducted from employee',
  `working_days` int NOT NULL DEFAULT '26' COMMENT 'Working days used for this run',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_emp_payroll_run` (`emp_id`,`payroll_month`),
  KEY `idx_run_emp_month` (`emp_id`,`payroll_month`),
  KEY `idx_run_status` (`status`),
  KEY `fk_run_processed_by` (`processed_by`),
  KEY `fk_run_created_by` (`created_by`),
  KEY `fk_run_modified_by` (`modified_by`),
  KEY `fk_epr_parent_run` (`parent_run_id`),
  CONSTRAINT `fk_epr_parent_run` FOREIGN KEY (`parent_run_id`) REFERENCES `emp_payroll_run` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_run_created_by` FOREIGN KEY (`created_by`) REFERENCES `usr` (`id`),
  CONSTRAINT `fk_run_emp_id` FOREIGN KEY (`emp_id`) REFERENCES `employee` (`id`),
  CONSTRAINT `fk_run_modified_by` FOREIGN KEY (`modified_by`) REFERENCES `usr` (`id`),
  CONSTRAINT `fk_run_processed_by` FOREIGN KEY (`processed_by`) REFERENCES `usr` (`id`),
  CONSTRAINT `chk_run_status` CHECK ((`status` in (_utf8mb4'DRAFT',_utf8mb4'PROCESSED',_utf8mb4'LOCKED',_utf8mb4'CORRECTION_DRAFT',_utf8mb4'CORRECTION_LOCKED')))
) ENGINE=InnoDB AUTO_INCREMENT=1508 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

