--
-- Table structure for table `emp_sal_adv`
--

DROP TABLE IF EXISTS `emp_sal_adv`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `emp_sal_adv` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `emp_id` bigint NOT NULL,
  `payroll_month` varchar(20) NOT NULL,
  `amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `is_processed` char(1) NOT NULL DEFAULT 'N',
  `processed_date` datetime DEFAULT NULL,
  `created_by` bigint NOT NULL,
  `created_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `modified_by` bigint NOT NULL,
  `modified_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `import_log_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_emp_sal_adv` (`emp_id`,`payroll_month`),
  KEY `fk_emp_sal_adv_emp_id` (`emp_id`),
  KEY `fk_emp_sal_adv_created_by` (`created_by`),
  KEY `fk_emp_sal_adv_modified_by` (`modified_by`),
  KEY `idx_emp_sal_adv_month` (`emp_id`,`payroll_month`),
  KEY `fk_emp_sal_adv_import_log` (`import_log_id`),
  CONSTRAINT `fk_emp_sal_adv_created_by` FOREIGN KEY (`created_by`) REFERENCES `usr` (`id`),
  CONSTRAINT `fk_emp_sal_adv_emp_id` FOREIGN KEY (`emp_id`) REFERENCES `employee` (`id`),
  CONSTRAINT `fk_emp_sal_adv_import_log` FOREIGN KEY (`import_log_id`) REFERENCES `import_log` (`id`),
  CONSTRAINT `fk_emp_sal_adv_modified_by` FOREIGN KEY (`modified_by`) REFERENCES `usr` (`id`),
  CONSTRAINT `chk_emp_sal_adv_processed` CHECK ((`is_processed` in (_utf8mb4'Y',_utf8mb4'N')))
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

