INSERT INTO `payslip_template` VALUES (1,'Standard - Portrait','<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Ideal Pay Salary Slip - Type 1 Single</title>\n</head>\n<body style=\"margin:0; padding:24px; background:#ffffff; color:#111111; font-family:\'Courier New\', Courier, monospace; font-size:12px; line-height:1.28;\">\n  <main style=\"width:100%; max-width:520px; margin:0 auto;\">\n    <section aria-label=\"Salary slip\" style=\"width:100%; box-sizing:border-box; padding:0; color:#111111;\">\n      <h1 style=\"margin:0 0 6px; font-size:13px; line-height:1.25; font-weight:700; letter-spacing:0; text-transform:uppercase;\">{{COMPANY_NAME}} SALARY SLIP &mdash; {{PAYROLL_MONTH}}</h1>\n      <div style=\"height:1px; background:#111111; margin:0 0 8px;\"></div>\n\n      <table role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" style=\"width:100%; border-collapse:collapse; table-layout:fixed; margin:0 0 8px;\">\n        <tr>\n          <td style=\"width:122px; padding:0 0 3px; white-space:nowrap; vertical-align:top;\">Employee No:</td>\n          <td style=\"padding:0 0 3px; vertical-align:top;\">{{EMPLOYEE_NO}}</td>\n        </tr>\n        <tr>\n          <td style=\"width:122px; padding:0 0 3px; white-space:nowrap; vertical-align:top;\">Employee Name:</td>\n          <td style=\"padding:0 0 3px; vertical-align:top;\">{{EMPLOYEE_NAME}}</td>\n        </tr>\n        <tr>\n          <td style=\"width:122px; padding:0 0 3px; white-space:nowrap; vertical-align:top;\">Department:</td>\n          <td style=\"padding:0 0 3px; vertical-align:top;\">{{DEPARTMENT}}</td>\n        </tr>\n        <tr>\n          <td style=\"width:122px; padding:0; white-space:nowrap; vertical-align:top;\">Designation:</td>\n          <td style=\"padding:0; vertical-align:top;\">{{DESIGNATION}}</td>\n        </tr>\n      </table>\n\n      <div style=\"height:1px; background:#111111; margin:0 0 7px;\"></div>\n      <div style=\"margin:0 0 7px; font-weight:700;\">Earnings</div>\n      <div style=\"height:1px; background:#111111; margin:0 0 5px;\"></div>\n\n      <table role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" style=\"width:100%; border-collapse:collapse; table-layout:fixed; margin:0 0 6px;\">\n        <colgroup>\n          <col align=\"left\" style=\"width:auto; text-align:left;\">\n          <col align=\"right\" style=\"width:140px; text-align:right;\">\n        </colgroup>\n        <tbody>\n          {{EARNINGS_ROWS}}\n        </tbody>\n      </table>\n\n      <div style=\"height:1px; background:#111111; margin:0 0 5px;\"></div>\n      <table role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" style=\"width:100%; border-collapse:collapse; table-layout:fixed; margin:0 0 7px;\">\n        <tr>\n          <td style=\"padding:0; font-weight:700;\">Gross Salary</td>\n          <td style=\"width:140px; padding:0; font-weight:700; text-align:right; white-space:nowrap;\">{{GROSS_PAY}}</td>\n        </tr>\n      </table>\n\n      <div style=\"height:1px; background:#111111; margin:0 0 7px;\"></div>\n      <div style=\"margin:0 0 7px; font-weight:700;\">Deductions</div>\n      <div style=\"height:1px; background:#111111; margin:0 0 5px;\"></div>\n\n      <table role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" style=\"width:100%; border-collapse:collapse; table-layout:fixed; margin:0 0 6px;\">\n        <colgroup>\n          <col align=\"left\" style=\"width:auto; text-align:left;\">\n          <col align=\"right\" style=\"width:140px; text-align:right;\">\n        </colgroup>\n        <tbody>\n          {{DEDUCTIONS_ROWS}}\n        </tbody>\n      </table>\n\n      <div style=\"height:1px; background:#111111; margin:0 0 5px;\"></div>\n      <table role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" style=\"width:100%; border-collapse:collapse; table-layout:fixed; margin:0 0 8px;\">\n        <tr>\n          <td style=\"padding:0; font-weight:700;\">Total Deduction</td>\n          <td style=\"width:140px; padding:0; font-weight:700; text-align:right; white-space:nowrap;\">{{TOTAL_DEDUCTIONS}}</td>\n        </tr>\n      </table>\n\n      <div style=\"border-top:1px solid #111111; border-bottom:1px solid #111111; padding:5px 0; margin:0 0 10px;\">\n        <table role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" style=\"width:100%; border-collapse:collapse; table-layout:fixed;\">\n          <tr>\n            <td style=\"padding:0; font-size:13px; font-weight:700;\">NET PAY</td>\n            <td style=\"width:140px; padding:0; font-size:13px; font-weight:700; text-align:right; white-space:nowrap;\">{{NET_PAY}}</td>\n          </tr>\n        </table>\n      </div>\n\n      <div style=\"margin:0 0 7px; font-weight:700;\">Employer Contributions</div>\n      <div style=\"height:1px; background:#111111; margin:0 0 5px;\"></div>\n      <table role=\"presentation\" cellspacing=\"0\" cellpadding=\"0\" style=\"width:100%; border-collapse:collapse; table-layout:fixed;\">\n        <colgroup>\n          <col align=\"left\" style=\"width:auto; text-align:left;\">\n          <col align=\"right\" style=\"width:140px; text-align:right;\">\n        </colgroup>\n        <tbody>\n          {{EMPLOYER_ROWS}}\n        </tbody>\n      </table>\n      <div style=\"height:1px; background:#111111; margin:6px 0 0;\"></div>\n    </section>\n  </main>\n</body>\n</html>','Y',1,1,'2026-06-05 01:43:43','2026-06-05 08:54:03'),(2,'Test2','<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\"/>\n  <style>\n\n    @page {\n      size: A4 portrait;\n      margin: 12mm 14mm 12mm 14mm;\n    }\n\n    * {\n      box-sizing: border-box;\n      margin: 0;\n      padding: 0;\n    }\n\n    body {\n      font-family: Arial, Helvetica, sans-serif;\n      font-size: 8.5pt;\n      color: #1e293b;\n      background: #ffffff;\n    }\n\n    /* ── HEADER ─────────────────────────────────────────── */\n\n    .header {\n      width: 100%;\n      border-bottom: 3pt solid #1e3a8a;\n      padding-bottom: 8pt;\n      margin-bottom: 8pt;\n    }\n\n    .header table {\n      width: 100%;\n      border: none;\n    }\n\n    .header td {\n      border: none;\n      padding: 0;\n      vertical-align: middle;\n    }\n\n    .logo {\n      width: 48pt;\n    }\n\n    .logo img {\n      width: 40pt;\n      height: 40pt;\n    }\n\n    .company-name {\n      font-size: 13pt;\n      font-weight: bold;\n      color: #1e3a8a;\n    }\n\n    .company-detail {\n      font-size: 7pt;\n      color: #64748b;\n      margin-top: 2pt;\n      line-height: 1.4;\n    }\n\n    .doc-info {\n      text-align: right;\n    }\n\n    .doc-title {\n      font-size: 14pt;\n      font-weight: bold;\n      color: #1e3a8a;\n      letter-spacing: 0.04em;\n    }\n\n    .doc-period {\n      font-size: 9pt;\n      color: #475569;\n      margin-top: 3pt;\n      font-weight: bold;\n    }\n\n    /* ── EMPLOYEE INFO ───────────────────────────────────── */\n\n    .emp-section {\n      background: #f1f5f9;\n      border-left: 3pt solid #1e3a8a;\n      padding: 7pt 10pt;\n      margin-bottom: 10pt;\n    }\n\n    .emp-section table {\n      width: 100%;\n      border: none;\n      border-collapse: collapse;\n    }\n\n    .emp-section td {\n      border: none;\n      padding: 2pt 6pt 2pt 0;\n      font-size: 7.5pt;\n      vertical-align: top;\n    }\n\n    .emp-key {\n      color: #64748b;\n      width: 68pt;\n      white-space: nowrap;\n    }\n\n    .emp-val {\n      font-weight: bold;\n      color: #0f172a;\n    }\n\n    .emp-divider {\n      width: 1pt;\n      background: #cbd5e1;\n      padding: 0 8pt;\n    }\n\n    /* ── EARNINGS / DEDUCTIONS ───────────────────────────── */\n\n    .columns {\n      width: 100%;\n      border: none;\n      border-collapse: collapse;\n      margin-bottom: 8pt;\n    }\n\n    .columns td {\n      border: none;\n      vertical-align: top;\n      width: 50%;\n      padding: 0;\n    }\n\n    .col-left  { padding-right: 5pt; }\n    .col-right { padding-left: 5pt;  }\n\n    .section-title {\n      font-size: 7pt;\n      font-weight: bold;\n      text-transform: uppercase;\n      letter-spacing: 0.06em;\n      color: #ffffff;\n      background: #1e3a8a;\n      padding: 3.5pt 7pt;\n    }\n\n    .pay-table {\n      width: 100%;\n      border-collapse: collapse;\n    }\n\n    .pay-table td {\n      font-size: 7.5pt;\n      padding: 3pt 7pt;\n      border-bottom: 0.5pt solid #f1f5f9;\n      color: #334155;\n    }\n\n    .pay-table td.amt {\n      text-align: right;\n      font-variant-numeric: tabular-nums;\n      white-space: nowrap;\n      color: #0f172a;\n    }\n\n    .pay-table tr.subtotal td {\n      font-weight: bold;\n      border-top: 1pt solid #cbd5e1;\n      border-bottom: none;\n      background: #f8fafc;\n      color: #0f172a;\n      font-size: 8pt;\n      padding-top: 4pt;\n      padding-bottom: 4pt;\n    }\n\n    /* ── NET PAY ─────────────────────────────────────────── */\n\n    .net-pay {\n      background: #1e3a8a;\n      color: #ffffff;\n      padding: 8pt 12pt;\n      margin-bottom: 8pt;\n    }\n\n    .net-pay table {\n      width: 100%;\n      border: none;\n    }\n\n    .net-pay td {\n      border: none;\n      color: #ffffff;\n      padding: 0;\n      vertical-align: middle;\n    }\n\n    .net-label {\n      font-size: 10pt;\n      font-weight: bold;\n      letter-spacing: 0.04em;\n    }\n\n    .net-sub {\n      font-size: 7pt;\n      color: #93c5fd;\n      margin-top: 2pt;\n    }\n\n    .net-amount {\n      font-size: 16pt;\n      font-weight: bold;\n      text-align: right;\n    }\n\n    .net-currency {\n      font-size: 9pt;\n      font-weight: normal;\n      color: #93c5fd;\n      margin-right: 3pt;\n    }\n\n    /* ── EMPLOYER CONTRIBUTIONS ──────────────────────────── */\n\n    .employer-section {\n      border: 0.5pt solid #e2e8f0;\n      padding: 5pt 8pt;\n      margin-bottom: 8pt;\n    }\n\n    .employer-heading {\n      font-size: 6.5pt;\n      font-weight: bold;\n      text-transform: uppercase;\n      letter-spacing: 0.05em;\n      color: #64748b;\n      margin-bottom: 4pt;\n    }\n\n    .employer-table {\n      width: 100%;\n      border-collapse: collapse;\n    }\n\n    .employer-table td {\n      font-size: 7pt;\n      color: #475569;\n      padding: 2pt 0;\n      border: none;\n    }\n\n    .employer-table td.amt {\n      text-align: right;\n      font-variant-numeric: tabular-nums;\n      color: #334155;\n    }\n\n    /* ── BANK & SIGNATURE ────────────────────────────────── */\n\n    .bottom-section table {\n      width: 100%;\n      border: none;\n      border-collapse: collapse;\n    }\n\n    .bottom-section td {\n      border: none;\n      vertical-align: bottom;\n      padding: 0;\n    }\n\n    .bank-box {\n      background: #f8fafc;\n      border: 0.5pt solid #e2e8f0;\n      padding: 5pt 8pt;\n      font-size: 7.5pt;\n    }\n\n    .bank-label {\n      font-size: 6.5pt;\n      color: #64748b;\n      text-transform: uppercase;\n      letter-spacing: 0.04em;\n      margin-bottom: 3pt;\n    }\n\n    .bank-val {\n      font-weight: bold;\n      color: #0f172a;\n    }\n\n    .signature-box {\n      text-align: right;\n      padding-left: 16pt;\n    }\n\n    .sig-line {\n      border-top: 1pt solid #334155;\n      width: 100pt;\n      margin-left: auto;\n      margin-top: 20pt;\n    }\n\n    .sig-label {\n      font-size: 7pt;\n      color: #64748b;\n      margin-top: 3pt;\n      text-align: center;\n      width: 100pt;\n      margin-left: auto;\n    }\n\n    /* ── FOOTER ──────────────────────────────────────────── */\n\n    .footer {\n      border-top: 0.5pt solid #e2e8f0;\n      padding-top: 5pt;\n      margin-top: 6pt;\n      font-size: 6.5pt;\n      color: #94a3b8;\n      text-align: center;\n      line-height: 1.5;\n    }\n\n  </style>\n</head>\n<body>\n\n  <!-- ══════════════════════════════════════════\n       HEADER — Logo · Company · Pay Slip label\n  ══════════════════════════════════════════ -->\n  <div class=\"header\">\n    <table>\n      <tr>\n        <td class=\"logo\">\n          <img src=\"{{COMPANY_LOGO}}\" alt=\"Logo\"/>\n        </td>\n        <td>\n          <div class=\"company-name\">{{COMPANY_NAME}}</div>\n          <div class=\"company-detail\">{{COMPANY_ADDRESS}}</div>\n          <div class=\"company-detail\">\n            Tel: {{COMPANY_PHONE}} &nbsp;|&nbsp; {{COMPANY_EMAIL}}\n          </div>\n          <div class=\"company-detail\">\n            EPF Reg No: {{COMPANY_EPF_NO}}\n          </div>\n        </td>\n        <td class=\"doc-info\">\n          <div class=\"doc-title\">PAY SLIP</div>\n          <div class=\"doc-period\">{{PAYROLL_MONTH}}</div>\n        </td>\n      </tr>\n    </table>\n  </div>\n\n  <!-- ══════════════════════════════════════════\n       EMPLOYEE DETAILS\n  ══════════════════════════════════════════ -->\n  <div class=\"emp-section\">\n    <table>\n      <tr>\n        <td class=\"emp-key\">Employee No.</td>\n        <td class=\"emp-val\">{{EMPLOYEE_NO}}</td>\n        <td class=\"emp-divider\"></td>\n        <td class=\"emp-key\">Department</td>\n        <td class=\"emp-val\">{{DEPARTMENT}}</td>\n      </tr>\n      <tr>\n        <td class=\"emp-key\">Name</td>\n        <td class=\"emp-val\">{{EMPLOYEE_NAME}}</td>\n        <td class=\"emp-divider\"></td>\n        <td class=\"emp-key\">Designation</td>\n        <td class=\"emp-val\">{{DESIGNATION}}</td>\n      </tr>\n      <tr>\n        <td class=\"emp-key\">EPF No.</td>\n        <td class=\"emp-val\">{{EMPLOYEE_EPF_NO}}</td>\n        <td class=\"emp-divider\"></td>\n        <td class=\"emp-key\">Working Days</td>\n        <td class=\"emp-val\">{{WORKING_DAYS}}</td>\n      </tr>\n    </table>\n  </div>\n\n  <!-- ══════════════════════════════════════════\n       EARNINGS  |  DEDUCTIONS  (two columns)\n  ══════════════════════════════════════════ -->\n  <table class=\"columns\">\n    <tr>\n\n      <!-- LEFT — Earnings -->\n      <td class=\"col-left\">\n        <div class=\"section-title\">Earnings</div>\n        <table class=\"pay-table\">\n          <tbody>\n            {{EARNINGS_ROWS}}\n          </tbody>\n          <tr class=\"subtotal\">\n            <td>Gross Pay</td>\n            <td class=\"amt\">{{GROSS_PAY}}</td>\n          </tr>\n        </table>\n      </td>\n\n      <!-- RIGHT — Deductions -->\n      <td class=\"col-right\">\n        <div class=\"section-title\">Deductions</div>\n        <table class=\"pay-table\">\n          <tbody>\n            {{DEDUCTIONS_ROWS}}\n          </tbody>\n          <tr class=\"subtotal\">\n            <td>Total Deductions</td>\n            <td class=\"amt\">{{TOTAL_DEDUCTIONS}}</td>\n          </tr>\n        </table>\n      </td>\n\n    </tr>\n  </table>\n\n  <!-- ══════════════════════════════════════════\n       NET PAY BANNER\n  ══════════════════════════════════════════ -->\n  <div class=\"net-pay\">\n    <table>\n      <tr>\n        <td>\n          <div class=\"net-label\">NET PAY</div>\n          <div class=\"net-sub\">Amount payable to employee</div>\n        </td>\n        <td>\n          <div class=\"net-amount\">\n            <span class=\"net-currency\">LKR</span>{{NET_PAY}}\n          </div>\n        </td>\n      </tr>\n    </table>\n  </div>\n\n  <!-- ══════════════════════════════════════════\n       EMPLOYER CONTRIBUTIONS\n  ══════════════════════════════════════════ -->\n  <div class=\"employer-section\">\n    <div class=\"employer-heading\">Employer Contributions &nbsp;(not deducted from employee)</div>\n    <table class=\"employer-table\">\n      <tbody>\n        {{EMPLOYER_ROWS}}\n      </tbody>\n    </table>\n  </div>\n\n  <!-- ══════════════════════════════════════════\n       BANK DETAILS  +  AUTHORISED SIGNATURE\n  ══════════════════════════════════════════ -->\n  <div class=\"bottom-section\">\n    <table>\n      <tr>\n        <td style=\"width:55%;\">\n          <div class=\"bank-box\">\n            <div class=\"bank-label\">Payment Details</div>\n            <div>\n              <span style=\"color:#64748b;\">Bank &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;:</span>\n              <span class=\"bank-val\"> {{BANK_NAME}}</span>\n            </div>\n            <div>\n              <span style=\"color:#64748b;\">Branch &nbsp;&nbsp;&nbsp;:</span>\n              <span class=\"bank-val\"> {{BANK_BRANCH}}</span>\n            </div>\n            <div>\n              <span style=\"color:#64748b;\">Account :</span>\n              <span class=\"bank-val\"> {{ACCOUNT_NO}}</span>\n            </div>\n          </div>\n        </td>\n        <td>\n          <div class=\"signature-box\">\n            <div class=\"sig-line\"></div>\n            <div class=\"sig-label\">Authorised Signature</div>\n          </div>\n        </td>\n      </tr>\n    </table>\n  </div>\n\n  <!-- ══════════════════════════════════════════\n       FOOTER\n  ══════════════════════════════════════════ -->\n  <div class=\"footer\">\n    This is a computer-generated payslip and does not require a physical signature.\n    &nbsp;|&nbsp; Confidential — for the named employee only.\n    &nbsp;|&nbsp; For queries contact HR.\n  </div>\n\n</body>\n</html>\n','Y',1,1,'2026-06-05 01:47:24','2026-06-05 04:16:32'),(3,'test','af','Y',1,1,'2026-06-05 04:16:17','2026-06-05 04:26:32'),(4,'No Pay Test','<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\"/>\n  <style>\n    @page {\n      size: A4 portrait;\n      margin: 14mm 14mm 12mm 14mm;\n    }\n\n    * { box-sizing: border-box; margin: 0; padding: 0; }\n\n    body {\n      font-family: Arial, Helvetica, sans-serif;\n      font-size: 11px;\n      color: #1a1a1a;\n      background: #ffffff;\n      line-height: 1.4;\n    }\n\n    /* ── Header ── */\n    .header {\n      display: table;\n      width: 100%;\n      margin-bottom: 10px;\n    }\n    .header-left, .header-right {\n      display: table-cell;\n      vertical-align: middle;\n    }\n    .header-right { text-align: right; }\n\n    .company-logo img {\n      max-height: 52px;\n      max-width: 140px;\n    }\n    .company-name {\n      font-size: 15px;\n      font-weight: bold;\n      color: #1a1a1a;\n    }\n    .company-meta {\n      font-size: 10px;\n      color: #555;\n      margin-top: 2px;\n    }\n    .doc-title {\n      font-size: 18px;\n      font-weight: bold;\n      letter-spacing: 1px;\n      color: #1a3a5c;\n    }\n    .doc-period {\n      font-size: 11px;\n      color: #444;\n      margin-top: 3px;\n    }\n\n    hr.divider {\n      border: none;\n      border-top: 1.5px solid #1a3a5c;\n      margin: 8px 0;\n    }\n    hr.thin {\n      border: none;\n      border-top: 1px solid #ddd;\n      margin: 6px 0;\n    }\n\n    /* ── Employee block ── */\n    .emp-grid {\n      display: table;\n      width: 100%;\n      margin-bottom: 8px;\n    }\n    .emp-col {\n      display: table-cell;\n      width: 50%;\n      vertical-align: top;\n    }\n    .emp-row {\n      display: table;\n      width: 100%;\n      margin-bottom: 3px;\n    }\n    .emp-label {\n      display: table-cell;\n      width: 42%;\n      font-weight: bold;\n      color: #555;\n      font-size: 10px;\n      text-transform: uppercase;\n      letter-spacing: 0.3px;\n    }\n    .emp-value {\n      display: table-cell;\n      color: #1a1a1a;\n      font-size: 11px;\n    }\n\n    /* ── Body: two columns ── */\n    .body-table {\n      display: table;\n      width: 100%;\n      border-collapse: collapse;\n      margin-bottom: 8px;\n    }\n    .col-earnings, .col-deductions {\n      display: table-cell;\n      width: 50%;\n      vertical-align: top;\n      padding: 0 4px;\n    }\n    .col-earnings { padding-left: 0; border-right: 1px solid #ddd; padding-right: 10px; }\n    .col-deductions { padding-left: 10px; }\n\n    .section-title {\n      font-size: 10px;\n      font-weight: bold;\n      text-transform: uppercase;\n      letter-spacing: 0.5px;\n      color: #1a3a5c;\n      background: #eef3f9;\n      padding: 3px 5px;\n      margin-bottom: 4px;\n    }\n\n    table.lines {\n      width: 100%;\n      border-collapse: collapse;\n    }\n    table.lines td {\n      padding: 2px 2px;\n      vertical-align: top;\n      font-size: 11px;\n    }\n    table.lines td.amt {\n      text-align: right;\n      white-space: nowrap;\n    }\n    table.lines tr.subtotal td {\n      border-top: 1px solid #ccc;\n      padding-top: 3px;\n      font-weight: bold;\n    }\n    table.lines tr.zero td {\n      color: #aaa;\n    }\n\n    /* ── Employer contributions ── */\n    .employer-section {\n      margin-top: 8px;\n    }\n\n    /* ── Net pay footer ── */\n    .net-pay-bar {\n      background: #1a3a5c;\n      color: #ffffff;\n      display: table;\n      width: 100%;\n      padding: 7px 10px;\n      margin-top: 10px;\n    }\n    .net-pay-label {\n      display: table-cell;\n      font-size: 13px;\n      font-weight: bold;\n      letter-spacing: 0.5px;\n    }\n    .net-pay-amount {\n      display: table-cell;\n      text-align: right;\n      font-size: 15px;\n      font-weight: bold;\n    }\n\n    /* ── Bank / account details ── */\n    .bank-block {\n      margin-top: 8px;\n      font-size: 10px;\n      color: #555;\n    }\n    .bank-block span { margin-right: 14px; }\n\n    /* ── Footer note ── */\n    .footer-note {\n      margin-top: 10px;\n      font-size: 9px;\n      color: #999;\n      text-align: center;\n    }\n  </style>\n</head>\n<body>\n\n  <!-- ════════════════════ HEADER ════════════════════ -->\n  <div class=\"header\">\n    <div class=\"header-left\">\n      <div class=\"company-logo\">\n        <!-- COMPANY_LOGO is a base64 data-URI or URL -->\n        <img src=\"{{COMPANY_LOGO}}\" alt=\"{{COMPANY_NAME}}\" onerror=\"this.style.display=\'none\'\"/>\n      </div>\n      <div class=\"company-name\">{{COMPANY_NAME}}</div>\n      <div class=\"company-meta\">{{COMPANY_ADDRESS}}</div>\n      <div class=\"company-meta\">{{lblCompanyName}} EPF: {{COMPANY_EPF_NO}} &nbsp;|&nbsp; ETF: {{COMPANY_ETF_NO}}</div>\n      <div class=\"company-meta\">Tel: {{COMPANY_PHONE}} &nbsp;|&nbsp; {{COMPANY_EMAIL}}</div>\n    </div>\n    <div class=\"header-right\">\n      <div class=\"doc-title\">PAY SLIP</div>\n      <div class=\"doc-period\">{{lblPayrollMonth}}: {{PAYROLL_MONTH}}</div>\n      <div class=\"doc-period\">{{lblWorkingDays}}: {{WORKING_DAYS}} days</div>\n    </div>\n  </div>\n\n  <hr class=\"divider\"/>\n\n  <!-- ════════════════════ EMPLOYEE INFO ════════════════════ -->\n  <div class=\"emp-grid\">\n    <div class=\"emp-col\">\n      <div class=\"emp-row\">\n        <span class=\"emp-label\">{{lblEmployeeName}}</span>\n        <span class=\"emp-value\">{{EMPLOYEE_NAME}}</span>\n      </div>\n      <div class=\"emp-row\">\n        <span class=\"emp-label\">{{lblEmployeeNo}}</span>\n        <span class=\"emp-value\">{{EMPLOYEE_NO}}</span>\n      </div>\n      <div class=\"emp-row\">\n        <span class=\"emp-label\">{{lblDesignation}}</span>\n        <span class=\"emp-value\">{{DESIGNATION}}</span>\n      </div>\n      <div class=\"emp-row\">\n        <span class=\"emp-label\">{{lblDepartment}}</span>\n        <span class=\"emp-value\">{{DEPARTMENT}}</span>\n      </div>\n    </div>\n    <div class=\"emp-col\">\n      <div class=\"emp-row\">\n        <span class=\"emp-label\">{{lblEpfNo}}</span>\n        <span class=\"emp-value\">{{EMPLOYEE_EPF_NO}}</span>\n      </div>\n      <div class=\"emp-row\">\n        <span class=\"emp-label\">{{lblBankName}}</span>\n        <span class=\"emp-value\">{{BANK_NAME}}</span>\n      </div>\n      <div class=\"emp-row\">\n        <span class=\"emp-label\">{{lblBankBranch}}</span>\n        <span class=\"emp-value\">{{BANK_BRANCH}}</span>\n      </div>\n      <div class=\"emp-row\">\n        <span class=\"emp-label\">{{lblAccountNo}}</span>\n        <span class=\"emp-value\">{{ACCOUNT_NO}}</span>\n      </div>\n    </div>\n  </div>\n\n  <hr class=\"divider\"/>\n\n  <!-- ════════════════════ EARNINGS / DEDUCTIONS ════════════════════ -->\n  <div class=\"body-table\">\n\n    <!-- ── Earnings column ── -->\n    <div class=\"col-earnings\">\n      <div class=\"section-title\">Earnings</div>\n      <table class=\"lines\">\n        <tbody>\n          <tr>\n            <td>{{lblBasicSalary}}</td>\n            <td class=\"amt\">{{BASIC_SALARY}}</td>\n          </tr>\n          <tr>\n            <td>{{lblFixedAllowance}}</td>\n            <td class=\"amt\">{{FIXED_ALLOWANCE}}</td>\n          </tr>\n          <tr>\n            <td>{{lblOvertime}}</td>\n            <td class=\"amt\">{{OVERTIME}}</td>\n          </tr>\n          <tr>\n            <td>{{lblVariableAllowance}}</td>\n            <td class=\"amt\">{{VARIABLE_ALLOWANCE}}</td>\n          </tr>\n          <tr>\n            <td>{{lblBonus}}</td>\n            <td class=\"amt\">{{BONUS}}</td>\n          </tr>\n          <tr>\n            <td>{{lblIncrement}}</td>\n            <td class=\"amt\">{{INCREMENT}}</td>\n          </tr>\n          <tr>\n            <td>{{lblGratuity}}</td>\n            <td class=\"amt\">{{GRATUITY}}</td>\n          </tr>\n          <!-- Dynamic rows (all earning components auto-inserted) -->\n          <!-- {{EARNINGS_ROWS}} -->\n          <tr class=\"subtotal\">\n            <td>{{lblGrossPay}}</td>\n            <td class=\"amt\">{{GROSS_PAY}}</td>\n          </tr>\n        </tbody>\n      </table>\n    </div>\n\n    <!-- ── Deductions column ── -->\n    <div class=\"col-deductions\">\n      <div class=\"section-title\">Deductions</div>\n      <table class=\"lines\">\n        <tbody>\n          <tr>\n            <td>{{lblNopay}}</td>\n            <td class=\"amt\">{{NOPAY}}</td>\n          </tr>\n          <tr>\n            <td>{{lblLateDeduction}}</td>\n            <td class=\"amt\">{{LATE_DEDUCTION}}</td>\n          </tr>\n          <tr>\n            <td>{{lblFixedDeduction}}</td>\n            <td class=\"amt\">{{FIXED_DEDUCTION}}</td>\n          </tr>\n          <tr>\n            <td>{{lblVariableDeduction}}</td>\n            <td class=\"amt\">{{VARIABLE_DEDUCTION}}</td>\n          </tr>\n          <tr>\n            <td>{{lblEpfEmployee}}</td>\n            <td class=\"amt\">{{EPF_EMPLOYEE}}</td>\n          </tr>\n          <tr>\n            <td>{{lblPayeTax}}</td>\n            <td class=\"amt\">{{PAYE_TAX}}</td>\n          </tr>\n          <!-- Dynamic rows (all deduction components auto-inserted) -->\n          <!-- {{DEDUCTIONS_ROWS}} -->\n          <tr class=\"subtotal\">\n            <td>{{lblTotalDeductions}}</td>\n            <td class=\"amt\">{{TOTAL_DEDUCTIONS}}</td>\n          </tr>\n        </tbody>\n      </table>\n\n      <!-- Employer contributions (for info only) -->\n      <div class=\"employer-section\">\n        <div class=\"section-title\">Employer Contributions</div>\n        <table class=\"lines\">\n          <tbody>\n            <tr>\n              <td>{{lblEpfEmployer}}</td>\n              <td class=\"amt\">{{EPF_EMPLOYER}}</td>\n            </tr>\n            <tr>\n              <td>{{lblEtf}}</td>\n              <td class=\"amt\">{{ETF}}</td>\n            </tr>\n          </tbody>\n        </table>\n      </div>\n    </div>\n\n  </div>\n\n  <hr class=\"divider\"/>\n\n  <!-- ════════════════════ NET PAY ════════════════════ -->\n  <div class=\"net-pay-bar\">\n    <span class=\"net-pay-label\">{{lblNetPay}}</span>\n    <span class=\"net-pay-amount\">{{NET_PAY}}</span>\n  </div>\n\n  <!-- ════════════════════ FOOTER ════════════════════ -->\n  <div class=\"footer-note\">\n    This is a computer-generated payslip and does not require a signature. &nbsp;|&nbsp; {{COMPANY_NAME}}\n  </div>\n\n{{OT001}} \n\n</body>\n</html>\n\n\n','Y',1,1,'2026-06-11 05:38:07','2026-06-11 16:33:26');
