CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_emp_sal_adv_pivot`(IN p_payroll_month VARCHAR(20))
BEGIN
    DECLARE v_sql LONGTEXT DEFAULT '';

    SET v_sql = CONCAT(
        'SELECT
            e.id,
            e.employee_no,
            e.first_name,
            e.last_name,
            e.payroll_name,
            e.basic_salary,
            IFNULL(sa.amount, 0)       AS sal_adv_amount,
            ''Salary Advance''         AS sal_adv_label,
            IFNULL(sa.is_processed, ''N'') AS is_processed,
            sa.processed_date
        FROM employee e
        LEFT JOIN emp_sal_adv sa
