            AND sa.payroll_month = ''', p_payroll_month, '''
        WHERE e.is_active = ''Y'' AND e.id > 0
        ORDER BY e.id'
    );

    SET @stmt = v_sql;
    PREPARE stmt FROM @stmt;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
