/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_payroll_run_review`(
    IN p_payroll_month VARCHAR(20)
)
BEGIN
    /*
     * Returns one row per employee × component for the given payroll month.
     *
     * Columns:
     *   emp_id           employee_no (display code)
     *   emp_name         first + last name
     *   component_type   FA | FD | VA | VD | OT | NOPAY | SA
     *   component_code   short code from master table
     *   component_name   human-readable label
     *   has_formula      Y / N  — whether a formula was configured on the master
     *   formula_expr     the formula string (NULL if none)
     *   before_value     amount entered in batch (source entry table)
     *   after_value      amount computed by the payroll engine (run detail)
     *   difference       after_value - before_value
     *   run_status       DRAFT | LOCKED | CORRECTION_DRAFT | CORRECTION_LOCKED
     *
     * "before" = the value recorded in emp_fa / emp_fd / emp_va / emp_vd /
     *            emp_ot / emp_np / emp_sal_adv at the time of batch entry.
     * "after"  = the value written to emp_payroll_run_detail by the engine.
     *
     * Statutory deductions (EPF_EE, EPF_ER, ETF, PAYE) are excluded because
     * they have no "entered" amount — they are always computed.
     */

    SELECT
        e.employee_no                                       AS emp_id,
        CONCAT(e.first_name, ' ', e.last_name)             AS emp_name,
        rd.component_type,
        rd.component_code,
        rd.component_name,

        -- formula flag from the component master
        CASE rd.component_type
            WHEN 'FA'    THEN COALESCE(fa.formula_enabled,  'N')
            WHEN 'FD'    THEN COALESCE(fd.formula_enabled,  'N')
            WHEN 'OT'    THEN COALESCE(ot.formula_enabled,  'N')
            WHEN 'NOPAY' THEN COALESCE(nd.formula_enabled,  'N')
            ELSE 'N'
        END                                                 AS has_formula,

        -- formula expression (informational only)
        CASE rd.component_type
            WHEN 'FA'    THEN fa.formula
            WHEN 'FD'    THEN fd.formula
            WHEN 'OT'    THEN ot.formula
            WHEN 'NOPAY' THEN nd.formula
            ELSE NULL
        END                                                 AS formula_expr,

        -- before value: what was entered in the batch source tables
        CASE rd.component_type
            WHEN 'FA'    THEN COALESCE(efa.amount,     0)
            WHEN 'FD'    THEN COALESCE(efd.amount,     0)
            WHEN 'VA'    THEN COALESCE(eva.amount,     0)
            WHEN 'VD'    THEN COALESCE(evd.amount,     0)
            WHEN 'OT'    THEN COALESCE(eot.amount,     0)
            WHEN 'NOPAY' THEN COALESCE(enp.amount,     0)
            WHEN 'SA'    THEN COALESCE(esa.amount,     0)
            ELSE rd.amount
        END                                                 AS before_value,

        -- after value: what the engine computed
        rd.amount                                           AS after_value,

        -- difference (positive = engine added value, negative = engine reduced)
        (rd.amount - CASE rd.component_type
            WHEN 'FA'    THEN COALESCE(efa.amount,     0)
            WHEN 'FD'    THEN COALESCE(efd.amount,     0)
            WHEN 'VA'    THEN COALESCE(eva.amount,     0)
            WHEN 'VD'    THEN COALESCE(evd.amount,     0)
            WHEN 'OT'    THEN COALESCE(eot.amount,     0)
            WHEN 'NOPAY' THEN COALESCE(enp.amount,     0)
            WHEN 'SA'    THEN COALESCE(esa.amount,     0)
            ELSE 0
        END)                                                AS difference,

        r.status                                            AS run_status

    FROM emp_payroll_run r

    JOIN employee e
        ON e.id = r.emp_id

    JOIN emp_payroll_run_detail rd
        ON rd.run_id = r.id

    -- ── Fixed Allowance ──────────────────────────────────────────────────
    LEFT JOIN fixed_allowance fa
        ON rd.component_type = 'FA'
       AND fa.code = rd.component_code

    LEFT JOIN emp_fa efa
        ON rd.component_type = 'FA'
       AND efa.emp_id   = r.emp_id
       AND efa.fa_id    = fa.id
       AND efa.payroll_month = p_payroll_month

    -- ── Fixed Deduction ──────────────────────────────────────────────────
    LEFT JOIN fixed_deduction fd
        ON rd.component_type = 'FD'
       AND fd.code = rd.component_code

    LEFT JOIN emp_fd efd
        ON rd.component_type = 'FD'
       AND efd.emp_id   = r.emp_id
       AND efd.fd_id    = fd.id
       AND efd.payroll_month = p_payroll_month

    -- ── Variable Allowance ───────────────────────────────────────────────
    LEFT JOIN variable_allowance va
        ON rd.component_type = 'VA'
       AND va.code = rd.component_code

    LEFT JOIN emp_va eva
        ON rd.component_type = 'VA'
       AND eva.emp_id   = r.emp_id
       AND eva.va_id    = va.id
       AND eva.payroll_month = p_payroll_month

    -- ── Variable Deduction ───────────────────────────────────────────────
    LEFT JOIN variable_deduction vd
        ON rd.component_type = 'VD'
       AND vd.code = rd.component_code

    LEFT JOIN emp_vd evd
        ON rd.component_type = 'VD'
       AND evd.emp_id   = r.emp_id
       AND evd.vd_id    = vd.id
       AND evd.payroll_month = p_payroll_month

    -- ── Overtime ─────────────────────────────────────────────────────────
    LEFT JOIN overtime ot
        ON rd.component_type = 'OT'
       AND ot.code = rd.component_code

    LEFT JOIN emp_ot eot
        ON rd.component_type = 'OT'
       AND eot.emp_id      = r.emp_id
       AND eot.overtime_id = ot.id
       AND eot.payroll_month = p_payroll_month

    -- ── NoPay ────────────────────────────────────────────────────────────
    LEFT JOIN nopay_days nd
        ON rd.component_type = 'NOPAY'
       AND nd.code = rd.component_code

    LEFT JOIN emp_np enp
        ON rd.component_type = 'NOPAY'
       AND enp.emp_id    = r.emp_id
       AND enp.nopay_id  = nd.id
       AND enp.payroll_month = p_payroll_month

    -- ── Salary Advance ────────────────────────────────────────────────────
    LEFT JOIN emp_sal_adv esa
        ON rd.component_type = 'SA'
       AND esa.emp_id        = r.emp_id
       AND esa.payroll_month = p_payroll_month

    WHERE r.payroll_month = p_payroll_month
      AND rd.component_type NOT IN ('EPF_EE', 'EPF_ER', 'ETF', 'PAYE')

    ORDER BY e.employee_no, rd.component_type, rd.component_name;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_payroll_monthly_detail` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_payroll_monthly_detail`(
    IN p_payroll_month VARCHAR(20)
)
BEGIN

    DECLARE v_fa LONGTEXT DEFAULT '';
    DECLARE v_va LONGTEXT DEFAULT '';
    DECLARE v_fd LONGTEXT DEFAULT '';
    DECLARE v_vd LONGTEXT DEFAULT '';
    DECLARE v_sql LONGTEXT DEFAULT '';

    SET SESSION group_concat_max_len = 1000000;

    /* =========================
       FIXED ALLOWANCE
    ========================= */
    SELECT GROUP_CONCAT(
        DISTINCT CONCAT(
            'SUM(CASE WHEN ef.fa_id = ', fa.id,
            ' THEN IFNULL(ef.amount,0) ELSE 0 END) AS `FA_',
            REPLACE(REPLACE(fa.name,' ','_'),'`',''),
            '`'
        )
        ORDER BY fa.id
        SEPARATOR ', '
    )
    INTO v_fa
    FROM fixed_allowance fa
    WHERE fa.is_active = 'Y';

    /* =========================
       VARIABLE ALLOWANCE
    ========================= */
    SELECT GROUP_CONCAT(
        DISTINCT CONCAT(
            'SUM(CASE WHEN eva.va_id = ', va.id,
            ' THEN IFNULL(eva.amount,0) ELSE 0 END) AS `VA_',
            REPLACE(REPLACE(va.name,' ','_'),'`',''),
            '`'
        )
        ORDER BY va.id
        SEPARATOR ', '
    )
    INTO v_va
    FROM variable_allowance va
    WHERE va.is_active = 'Y';

    /* =========================
       FIXED DEDUCTION
    ========================= */
    SELECT GROUP_CONCAT(
        DISTINCT CONCAT(
            'SUM(CASE WHEN efd.fd_id = ', fd.id,
            ' THEN IFNULL(efd.amount,0) ELSE 0 END) AS `FD_',
            REPLACE(REPLACE(fd.name,' ','_'),'`',''),
            '`'
        )
        ORDER BY fd.id
        SEPARATOR ', '
    )
    INTO v_fd
    FROM fixed_deduction fd
    WHERE fd.is_active = 'Y';

    /* =========================
       VARIABLE DEDUCTION
    ========================= */
    SELECT GROUP_CONCAT(
        DISTINCT CONCAT(
            'SUM(CASE WHEN evd.vd_id = ', vd.id,
            ' THEN IFNULL(evd.amount,0) ELSE 0 END) AS `VD_',
            REPLACE(REPLACE(vd.name,' ','_'),'`',''),
            '`'
        )
        ORDER BY vd.id
        SEPARATOR ', '
    )
    INTO v_vd
    FROM variable_deduction vd
    WHERE vd.is_active = 'Y';

    /* =========================
       FINAL QUERY
    ========================= */
    SET v_sql = CONCAT(
        'SELECT
            e.id,
            e.employee_no,
            e.first_name,
            e.last_name,
            e.payroll_name,
            e.basic_salary',

        IF(v_fa <> '', CONCAT(', ', v_fa), ''),
        IF(v_va <> '', CONCAT(', ', v_va), ''),
        IF(v_fd <> '', CONCAT(', ', v_fd), ''),
        IF(v_vd <> '', CONCAT(', ', v_vd), ''),

        ', 
        IFNULL((SELECT SUM(eot.amount)
                FROM emp_ot eot
                WHERE eot.emp_id = e.id
                AND eot.payroll_month = ''', p_payroll_month, '''),0) AS overtime_total,

        IFNULL((SELECT SUM(enp.amount)
                FROM emp_np enp
                WHERE enp.emp_id = e.id
                AND enp.payroll_month = ''', p_payroll_month, '''),0) AS nopay_total,

        (
            e.basic_salary +
            IFNULL((SELECT SUM(ef.amount) FROM emp_fa ef WHERE ef.emp_id = e.id AND ef.payroll_month = ''', p_payroll_month, '''),0) +
            IFNULL((SELECT SUM(eva.amount) FROM emp_va eva WHERE eva.emp_id = e.id AND eva.payroll_month = ''', p_payroll_month, '''),0)
        ) AS gross_salary,

        (
            IFNULL((SELECT SUM(efd.amount) FROM emp_fd efd WHERE efd.emp_id = e.id AND efd.payroll_month = ''', p_payroll_month, '''),0) +
            IFNULL((SELECT SUM(evd.amount) FROM emp_vd evd WHERE evd.emp_id = e.id AND evd.payroll_month = ''', p_payroll_month, '''),0) +
            IFNULL((SELECT SUM(enp.amount) FROM emp_np enp WHERE enp.emp_id = e.id AND enp.payroll_month = ''', p_payroll_month, '''),0)
        ) AS total_deductions,

        (
            (
                e.basic_salary +
                IFNULL((SELECT SUM(ef.amount) FROM emp_fa ef WHERE ef.emp_id = e.id AND ef.payroll_month = ''', p_payroll_month, '''),0) +
                IFNULL((SELECT SUM(eva.amount) FROM emp_va eva WHERE eva.emp_id = e.id AND eva.payroll_month = ''', p_payroll_month, '''),0)
            )
            -
            (
                IFNULL((SELECT SUM(efd.amount) FROM emp_fd efd WHERE efd.emp_id = e.id AND efd.payroll_month = ''', p_payroll_month, '''),0) +
                IFNULL((SELECT SUM(evd.amount) FROM emp_vd evd WHERE evd.emp_id = e.id AND evd.payroll_month = ''', p_payroll_month, '''),0) +
                IFNULL((SELECT SUM(enp.amount) FROM emp_np enp WHERE enp.emp_id = e.id AND enp.payroll_month = ''', p_payroll_month, '''),0)
            )
        ) AS net_salary

        FROM employee e

        LEFT JOIN emp_fa ef ON e.id = ef.emp_id AND ef.payroll_month = ''', p_payroll_month, '''
        LEFT JOIN emp_va eva ON e.id = eva.emp_id AND eva.payroll_month = ''', p_payroll_month, '''
        LEFT JOIN emp_fd efd ON e.id = efd.emp_id AND efd.payroll_month = ''', p_payroll_month, '''
        LEFT JOIN emp_vd evd ON e.id = evd.emp_id AND evd.payroll_month = ''', p_payroll_month, '''

        WHERE e.is_active = ''Y''

        GROUP BY
            e.id,
            e.employee_no,
            e.first_name,
            e.last_name,
            e.payroll_name,
            e.basic_salary

        ORDER BY e.id'
    );

    /* DEBUG */
    SELECT v_sql;

    /* EXECUTE */
    SET @stmt = v_sql;
    PREPARE stmt FROM @stmt;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_payroll_monthly_summary` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_payroll_monthly_summary`(
    IN p_payroll_month VARCHAR(20)
)
BEGIN
    SELECT
        e.employee_no AS Employee,
        e.basic_salary AS Basic,
        /* =========================
           TOTAL ALLOWANCES (FA + VA)
        ========================= */
        (
            IFNULL((SELECT SUM(ef.amount)
                    FROM emp_fa ef
                    WHERE ef.emp_id = e.id
                    AND ef.payroll_month = p_payroll_month),0)
            +
            IFNULL((SELECT SUM(eva.amount)
                    FROM emp_va eva
                    WHERE eva.emp_id = e.id
                    AND eva.payroll_month = p_payroll_month),0)
        ) AS Allowances,
        /* =========================
           OVERTIME
        ========================= */
        IFNULL((SELECT SUM(eot.amount)
                FROM emp_ot eot
                WHERE eot.emp_id = e.id
                AND eot.payroll_month = p_payroll_month),0) AS OT,
        /* =========================
           GROSS
        ========================= */
        (
            e.basic_salary
            +
            IFNULL((SELECT SUM(ef.amount)
                    FROM emp_fa ef
                    WHERE ef.emp_id = e.id
                    AND ef.payroll_month = p_payroll_month),0)
            +
            IFNULL((SELECT SUM(eva.amount)
                    FROM emp_va eva
                    WHERE eva.emp_id = e.id
                    AND eva.payroll_month = p_payroll_month),0)
            +
            IFNULL((SELECT SUM(eot.amount)
                    FROM emp_ot eot
                    WHERE eot.emp_id = e.id
                    AND eot.payroll_month = p_payroll_month),0)
        ) AS Gross,
        /* =========================
           DEDUCTIONS
        ========================= */
        (
            IFNULL((SELECT SUM(efd.amount)
                    FROM emp_fd efd
                    WHERE efd.emp_id = e.id
                    AND efd.payroll_month = p_payroll_month),0)
            +
            IFNULL((SELECT SUM(evd.amount)
                    FROM emp_vd evd
                    WHERE evd.emp_id = e.id
                    AND evd.payroll_month = p_payroll_month),0)
            +
            IFNULL((SELECT SUM(enp.amount)
                    FROM emp_np enp
                    WHERE enp.emp_id = e.id
                    AND enp.payroll_month = p_payroll_month),0)
        ) AS Deductions,
        /* =========================
           NET
        ========================= */
        (
            (
                e.basic_salary
                +
                IFNULL((SELECT SUM(ef.amount)
                        FROM emp_fa ef
                        WHERE ef.emp_id = e.id
                        AND ef.payroll_month = p_payroll_month),0)
                +
                IFNULL((SELECT SUM(eva.amount)
                        FROM emp_va eva
                        WHERE eva.emp_id = e.id
                        AND eva.payroll_month = p_payroll_month),0)
                +
                IFNULL((SELECT SUM(eot.amount)
                        FROM emp_ot eot
                        WHERE eot.emp_id = e.id
                        AND eot.payroll_month = p_payroll_month),0)
            )
            -
            (
                IFNULL((SELECT SUM(efd.amount)
                        FROM emp_fd efd
                        WHERE efd.emp_id = e.id
                        AND efd.payroll_month = p_payroll_month),0)
                +
                IFNULL((SELECT SUM(evd.amount)
                        FROM emp_vd evd
                        WHERE evd.emp_id = e.id
                        AND evd.payroll_month = p_payroll_month),0)
                +
                IFNULL((SELECT SUM(enp.amount)
                        FROM emp_np enp
                        WHERE enp.emp_id = e.id
                        AND enp.payroll_month = p_payroll_month),0)
            )
        ) AS Net
    FROM employee e
    WHERE e.is_active = 'Y'
    ORDER BY e.id;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_rpt_apitMonthly` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
