CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_rpt_apitMonthly`(IN p_payroll_month VARCHAR(20))
BEGIN
    SELECT
        e.employee_no                                      AS empCode,
        e.payroll_name                                     AS empName,
        e.nic                                              AS nic,
        r.gross_pay                                        AS grossIncome,
        (r.gross_pay - r.employee_epf)                     AS taxableIncome,
        r.paye_tax                                         AS taxDeducted,
        r.payroll_month                                    AS period
    FROM employee e
    JOIN emp_payroll_run r ON r.emp_id = e.id AND r.payroll_month = p_payroll_month
    WHERE e.is_active = 'Y'
    ORDER BY e.employee_no;
END ;;
