CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_rpt_bankTransfer`(IN p_payroll_month VARCHAR(20))
BEGIN
    SELECT
        e.employee_no                                                       AS empCode,
        e.payroll_name                                                      AS empName,
        bk.name                                                             AS bankName,
        e.account_no                                                        AS accountNo,
        bb.branch_code                                                      AS branchCode,
        r.net_pay                                                           AS amount,
        CASE WHEN tl.id IS NOT NULL THEN 'TRANSFERRED' ELSE 'PENDING' END   AS transferStatus
    FROM employee e
    JOIN emp_payroll_run r ON r.emp_id = e.id AND r.payroll_month = p_payroll_month
    LEFT JOIN bank bk ON bk.id = e.bank_id
    LEFT JOIN bank_branch bb ON bb.id = e.bank_branch_id
    LEFT JOIN emp_transfer_log tl ON tl.payroll_run_id = r.id AND tl.transfer_type = 'SALARY'
    WHERE e.is_active = 'Y'
      AND e.account_no IS NOT NULL
    ORDER BY e.employee_no;
END ;;
