CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_rpt_epfMonthly`(IN p_payroll_month VARCHAR(20))
BEGIN
    SELECT
        e.employee_no                          AS empCode,
        e.payroll_name                         AS empName,
        e.nic                                  AS nic,
        e.epf_no                               AS epfNo,
        r.epf_liable_base                      AS basicSalary,
        r.employee_epf                         AS employeeContribution,
        r.employer_epf                         AS employerContribution,
        (r.employee_epf + r.employer_epf)      AS totalContribution,
        r.payroll_month                        AS period
    FROM employee e
    JOIN emp_payroll_run r ON r.emp_id = e.id AND r.payroll_month = p_payroll_month
    WHERE e.is_active = 'Y'
    ORDER BY e.employee_no;
END ;;
