CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_rpt_nopay`(IN p_payroll_month VARCHAR(20))
BEGIN
    SELECT
        e.employee_no      AS empCode,
        e.payroll_name     AS empName,
        b.name             AS department,
        enp.days           AS nopayDays,
        enp.amount         AS nopayAmount,
        nd.name            AS reason,
        enp.payroll_month  AS period
    FROM emp_np enp
    JOIN employee e ON e.id = enp.emp_id
    LEFT JOIN nopay_days nd ON nd.id = enp.nopay_id
    LEFT JOIN branch b ON b.id = e.branch_id
    WHERE enp.payroll_month = p_payroll_month
      AND enp.days > 0
    ORDER BY e.employee_no;
END ;;
