CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_rpt_payrollSummary`(IN p_payroll_month VARCHAR(20))
BEGIN
    SELECT
        e.employee_no                          AS empCode,
        e.payroll_name                         AS empName,
        b.name                                 AS department,
        r.basic_salary                         AS basicSalary,
        (r.basic_salary + r.total_allowances)  AS totalEarnings,
        r.total_deductions                     AS totalDeductions,
        r.net_pay                              AS netPay,
        r.status                               AS status
    FROM employee e
    JOIN emp_payroll_run r ON r.emp_id = e.id AND r.payroll_month = p_payroll_month
    LEFT JOIN branch b ON b.id = e.branch_id
    WHERE e.is_active = 'Y'
    ORDER BY e.employee_no;
END ;;
